+    #[test]
+    fn nanargmin_matches_numpy_across_axes_keepdims_and_all_nan_errors() {
+        with_python(|py| {
+            if !numpy_available(py) {
+                return Ok(());
+            }
+
+            let module = PyModule::new(py, "fnp_python_test")?;
+            fnp_python(&module)?;
+            let nanargmin_fn = module.getattr("nanargmin")?;
+            let numpy = py.import("numpy")?;
+            let numpy_nanargmin = numpy.getattr("nanargmin")?;
+
+            // 1-D with NaN ignored.
+            let with_nan =
+                numpy
+                    .getattr("array")?
+                    .call1((vec![4.0_f64, 2.0, f64::NAN, 1.0, 3.0],))?;
+            let ours = nanargmin_fn.call1((with_nan.clone(),))?;
+            let theirs = numpy_nanargmin.call1((with_nan.clone(),))?;
+            assert_eq!(
+                repr_string(&ours),
+                repr_string(&theirs),
+                "nanargmin 1-D with NaN mismatch",
+            );
+
+            // 2-D mixed NaN with axis reductions.
+            let two_d = numpy.getattr("array")?.call1((vec![
+                vec![1.0_f64, f64::NAN, 3.0],
+                vec![4.0, 2.0, f64::NAN],
+                vec![f64::NAN, 8.0, 9.0],
+            ],))?;
+            for axis in [0_i64, 1] {
+                let ours_ax = nanargmin_fn.call(
+                    (two_d.clone(),),
+                    Some(&{
+                        let kw = PyDict::new(py);
+                        kw.set_item("axis", axis)?;
+                        kw
+                    }),
+                )?;
+                let theirs_ax = numpy_nanargmin.call(
+                    (two_d.clone(),),
+                    Some(&{
+                        let kw = PyDict::new(py);
+                        kw.set_item("axis", axis)?;
+                        kw
+                    }),
+                )?;
+                assert_array_matches_numpy(&ours_ax, &theirs_ax)?;
+            }
+
+            // keepdims=True preserves reduced axes.
+            let ours_kd = nanargmin_fn.call(
+                (two_d.clone(),),
+                Some(&{
+                    let kw = PyDict::new(py);
+                    kw.set_item("axis", 1_i64)?;
+                    kw.set_item("keepdims", true)?;
+                    kw
+                }),
+            )?;
+            let theirs_kd = numpy_nanargmin.call(
+                (two_d.clone(),),
+                Some(&{
+                    let kw = PyDict::new(py);
+                    kw.set_item("axis", 1_i64)?;
+                    kw.set_item("keepdims", true)?;
+                    kw
+                }),
+            )?;
+            assert_array_matches_numpy(&ours_kd, &theirs_kd)?;
+
+            // All-NaN slices must raise ValueError with numpy-matching text.
+            let all_nan = numpy
+                .getattr("array")?
+                .call1((vec![f64::NAN, f64::NAN, f64::NAN],))?;
+            let actual_err = nanargmin_fn.call1((all_nan.clone(),)).unwrap_err();
+            let expected_err = numpy_nanargmin.call1((all_nan.clone(),)).unwrap_err();
+            assert!(actual_err.is_instance_of::<PyValueError>(py));
+            assert!(expected_err.is_instance_of::<PyValueError>(py));
+            assert_eq!(actual_err.to_string(), expected_err.to_string());
+
+            // Integer input matches numpy.argmin semantics.
+            let ints = numpy
+                .getattr("array")?
+                .call1((vec![3_i64, 1, 4, 1, 5, 9, 2],))?;
+            let ours_i = nanargmin_fn.call1((ints.clone(),))?;
+            let theirs_i = numpy_nanargmin.call1((ints.clone(),))?;
+            assert_eq!(
+                repr_string(&ours_i),
+                repr_string(&theirs_i),
+                "nanargmin integer input mismatch",
+            );
+
+            // Ties choose the first minimal index just like numpy.
+            let tied = numpy
+                .getattr("array")?
+                .call1((vec![5.0_f64, 1.0, f64::NAN, 1.0, 4.0],))?;
+            let ours_tied = nanargmin_fn.call1((tied.clone(),))?;
+            let theirs_tied = numpy_nanargmin.call1((tied.clone(),))?;
+            assert_eq!(
+                repr_string(&ours_tied),
+                repr_string(&theirs_tied),
+                "nanargmin tie handling mismatch",
+            );
+
+            Ok(())
+        });
+    }
